Set-StrictMode -Version 2.0
function Get-GodModeBestArtifact { param([string]$Project='.') $r=Initialize-GodModeStructure $Project; $latest=Get-ChildItem (Join-GodModePath $r 'logs') -Filter 'validation-*.log' -ErrorAction SilentlyContinue|sort LastWriteTime -Descending|select -First 1; if($latest){return @{type='validation_log';path=$latest.FullName;exists=$true;hash=Get-GodModeFileHash $latest.FullName}}; $dash=Join-GodModePath $r 'graphs/latest-dashboard.md'; if(Test-Path $dash){return @{type='dashboard_markdown';path=$dash;exists=$true;hash=Get-GodModeFileHash $dash}}; @{type='none';path=$null;exists=$false;hash=$null} }
